// components/HomeHeader/index.tsx

"use client";
import React, { useState, useEffect, useRef } from "react";
import Image from "next/image";
import Link from "next/link";
import styles from "./styles.module.scss";

// Import icons (make sure the paths are correct)
import mobile from "@/app/assets/images/iconHomeCategories/mobile.png";
import tablet from "@/app/assets/images/iconHomeCategories/table.png";
import laptop from "@/app/assets/images/iconHomeCategories/laptop.png";
import tv from "@/app/assets/images/iconHomeCategories/tv.png";
import accessories from "@/app/assets/images/iconHomeCategories/game.png";
import smartwatch from "@/app/assets/images/iconHomeCategories/smartwatch.png";
import headphone from "@/app/assets/images/iconHomeCategories/headphone.png";
import repair from "@/app/assets/images/iconHomeCategories/repair.png";


export default function HomeHeader() {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isHeaderVisible, setIsHeaderVisible] = useState(true);
  const headerRef = useRef<HTMLElement>(null);
  let lastScrollY = useRef(0);

  const categories = [
    {
      name: "Điện thoại",
      image: mobile,
      subcategories: ["iPhone", "Samsung", "Xiaomi", "Other"],
    },
    {
      name: "Máy tính bảng",
      image: tablet,
      subcategories: ["iPad", "Samsung Tab", "Lenovo Tab", "Other"],
    },
    {
      name: "Laptop",
      image: laptop,
      subcategories: ["MacBook", "Dell", "HP", "Lenovo"],
    },
    {
      name: "Đồng hồ",
      image: smartwatch,
      subcategories: ["Apple Watch", "Samsung Watch", "Fitbit", "Other"],
    },
    {
      name: "Tivi",
      image: tv,
      subcategories: ["Samsung TV", "LG TV", "Sony TV", "Other"],
    },
    {
      name: "Phụ kiện",
      image: accessories,
      subcategories: ["Cases", "Chargers", "Headphones", "Screen Protectors"],
    },
    {
      name: "Tai nghe",
      image: headphone,
      subcategories: ["AirPods", "Headphones", "Bluetooth Speakers", "Other"],
    },
    {
      name: "Sửa chữa",
      image: repair,
      subcategories: [
        "Screen Repair",
        "Battery Replacement",
        "Water Damage",
        "Other",
      ],
    },
  ];

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollY = window.scrollY;

      if (currentScrollY > 50) {
        setIsScrolled(true);
      } else {
        setIsScrolled(false);
      }

      if (currentScrollY > lastScrollY.current && currentScrollY > 100) {
        setIsHeaderVisible(false);
      } else {
        setIsHeaderVisible(true);
      }

      lastScrollY.current = currentScrollY;
    };

    window.addEventListener("scroll", handleScroll);

    return () => {
      window.removeEventListener("scroll", handleScroll);
    };
  }, []);

  const renderCategories = () => (
    <div className={styles.categoriesContainer}>
      {categories.map((category) => (
        <div key={category.name} className={styles.categoryItem}>
          <Link href="#" className={styles.categoryLink}>
            <Image
              src={category.image}
              alt={category.name}
              width={30}
              height={30}
            />
            <span>{category.name}</span>
          </Link>
          <ul className={styles.subcategoryList}>
            {category.subcategories.map((subcategory) => (
              <li key={subcategory} className={styles.subCategoryListItem}>
                <Link href="#">{subcategory}</Link>
              </li>
            ))}
          </ul>
        </div>
      ))}
    </div>
  );

  return (
    <>
      <header
        className={`${styles.header} ${isScrolled ? styles.headerFixed : ""} ${!isHeaderVisible ? styles.headerHidden : ""}`}
        ref={headerRef}
      >
        <nav className={styles.nav}>
          <div className={styles.logo}>iPhone Store</div>
          <div className={styles.headerActions}>
            <div className={styles.searchBox}>
              <input type="text" placeholder="Tìm kiếm..." />
            </div>
          </div>
          <ul className={styles.menu}>
            <li>
              <Link href="#">Trang Chủ</Link>
            </li>
            <li>
              <Link href="#">Tin Tức</Link>
            </li>
            <li>
              <Link href="#">Giới Thiệu</Link>
            </li>
            <li>
              <Link href="#">Liên Hệ</Link>
            </li>
            <li>
              <Link href="#contact">Người Dùng</Link>
              <ul className={styles.dropdown}>
                <li>
                  <Link href="#">Đăng Nhập</Link>
                </li>
                <li>
                  <Link href="#">Đăng Ký</Link>
                </li>
                <li>
                  <Link href="#">Quên Mật Khẩu</Link>
                </li>
              </ul>
            </li>
          </ul>
        </nav>
        {!isScrolled && renderCategories()}
      </header>
        {isScrolled && (
        <div className={styles.floatingCategories} ref={headerRef}>
          {renderCategories()}
        </div>
      )}
    </>
  );
}